const d = $input.first().json.body;
if (d.event !== 'ticket_created') return [];

const ADMIN_PHONE = '573126402098';
const t = d.ticket;
const pEmoji = { Urgente: '🚨', Alta: '⚠️', Média: '📋', Baixa: '📝' }[t.priority] || '📋';
const devTag = t.is_dev ? '\n🛠️ *Tipo:* Demandas Tech' : '';

const message =
  `🎫 *Novo Ticket — BrokerDesk*\n\n` +
  `${pEmoji} *Prioridade:* ${t.priority}\n` +
  `🏢 *Broker:* ${t.broker}\n` +
  `📋 *Título:* ${t.title}\n` +
  `👤 *Aberto por:* ${t.created_by}` +
  devTag +
  `\n\n🕐 ${new Date().toLocaleString('pt-BR')}`;

return [{ json: { phone: ADMIN_PHONE, message } }];

const d = $input.first().json.body;
if (d.event !== 'ticket_resolved') return [];

const ADMIN_PHONE = '573126402098';
const t = d.ticket;

const message =
  `✅ *Ticket Resolvido — BrokerDesk*\n\n` +
  `🏢 *Broker:* ${t.broker}\n` +
  `📋 *Título:* ${t.title}\n` +
  `👤 *Resolvido por:* ${t.resolved_by || 'Operador'}\n\n` +
  `🕐 ${new Date().toLocaleString('pt-BR')}`;

return [{ json: { phone: ADMIN_PHONE, message } }];

const d = $input.first().json.body;
if (d.event !== 'routine_task_completed') return [];

const ADMIN_PHONE = '573126402098';
const task = d.task;
const cat = { manha: '🌅 Manhã', tarde: '🌇 Tarde', custom: '📌 Extra' }[task.category] || task.category;

const message =
  `☑️ *Tarefa de Rotina Concluída — BrokerDesk*\n\n` +
  `📋 *Tarefa:* ${task.title}\n` +
  `🗂️ *Período:* ${cat}\n` +
  `👤 *Operador:* ${task.completed_by || 'Operador'}\n\n` +
  `🕐 ${new Date().toLocaleString('pt-BR')}`;

return [{ json: { phone: ADMIN_PHONE, message } }];

const d = $input.first().json.body;
if (d.event !== 'admin_notification') return [];

const OPERATOR_PHONES = ['5512981963736', '5512982871400', '573126402098'];
const notif = d.notification;
const emojis = { info: 'ℹ️', success: '✅', warning: '⚠️', error: '🚨' };
const emoji = emojis[notif.type] || 'ℹ️';

const message =
  `${emoji} *BrokerDesk — ${notif.title}*\n\n` +
  `${notif.message}\n\n` +
  `🕐 ${new Date().toLocaleString('pt-BR')}`;

return OPERATOR_PHONES.map(phone => ({ json: { phone, message } }));

const d = $input.first().json.body;
if (d.event !== 'overdue_check' || !d.tickets || d.tickets.length === 0) return [];

const OPERATOR_PHONES = ['5512981963736', '5512982871400', '573126402098'];

const lines = d.tickets.map(t =>
  `• *${t.broker}* — ${t.titulo}\n  📅 Criado: ${new Date(t.data_criacao).toLocaleDateString('pt-BR')} (${t.dias_em_aberto} dia${t.dias_em_aberto > 1 ? 's' : ''} em aberto)`
).join('\n\n');

const message =
  `🚨 *BrokerDesk — Demandas Atrasadas*\n\n` +
  `${d.tickets.length} ticket${d.tickets.length > 1 ? 's' : ''} pendente${d.tickets.length > 1 ? 's' : ''} há mais de 3 dias:\n\n` +
  lines +
  `\n\n⚠️ Ação necessária!\n🕐 ${new Date().toLocaleString('pt-BR')}`;

return OPERATOR_PHONES.map(phone => ({ json: { phone, message } }));

const OPERATOR_PHONES = ['5512981963736', '5512982871400', '573126402098'];

const tickets = $input.all().map(i => i.json);
const pending = tickets.filter(t => t.status === 'Pendente');
const inProgress = tickets.filter(t => t.status === 'Em Andamento');
const urgent = tickets.filter(t => t.priority === 'Urgente');

const uniqueBrokers = [...new Set(pending.map(t => t.broker_nome || t.broker))];
const brokerList = uniqueBrokers.length > 0
  ? uniqueBrokers.map(b => `• ${b}`).join('\n')
  : '✅ Nenhuma pendência!';

const today = new Date().toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' });

const message =
  `📋 *BrokerDesk — Rotina do Dia*\n\n` +
  `📅 ${today}\n\n` +
  `⏳ *Pendentes:* ${pending.length}\n` +
  `▶️ *Em Andamento:* ${inProgress.length}\n` +
  `🚨 *Urgentes:* ${urgent.length}\n\n` +
  `🔴 *Brokers com pendências:*\n${brokerList}\n\n` +
  `Bom trabalho, equipe! 💪`;

return OPERATOR_PHONES.map(phone => ({ json: { phone, message } }));
